const body = $input.first().json.body;
const notificationId = body.notification_id;
const participantDetails = body.participant_details || {};

return body.members.map(member => ({
  json: {
    notification_id: notificationId,
    participant_details: participantDetails,
    first_name: (member.first_name || 'Admin').trim(),
    last_name: (member.last_name || '').trim(),
    phone: member.phone || '',
    email: member.email
  }
}));

const data = $input.item.json;
const adminName = `${data.first_name} ${data.last_name}`.trim() || 'there';
const pd = data.participant_details || {};
const userName = (pd.name || '').trim() || 'Unknown user';
const userPhone = pd.phone || pd.contact_input || '—';
const userEmail = pd.email || '—';
const queryText = pd.query_text || '—';
const ticketId = pd.ticket_id || data.notification_id;
const adminPanelUrl = 'https://admin.supershyft.com/support';

const escapeHtml = (value) => String(value)
  .replace(/&/g, '&amp;')
  .replace(/</g, '&lt;')
  .replace(/>/g, '&gt;')
  .replace(/"/g, '&quot;');

const htmlBody = `<!DOCTYPE html>
<html>
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <style>
    * { margin: 0; padding: 0; box-sizing: border-box; }
    body { font-family: Arial, sans-serif; background-color: #f0f2f5; color: #333; -webkit-text-size-adjust: 100%; }
    .wrapper { background-color: #f0f2f5; padding: 24px 12px; }
    .container { max-width: 520px; margin: 0 auto; background-color: #ffffff; border-radius: 16px; overflow: hidden; box-shadow: 0 4px 24px rgba(0,0,0,0.10); width: 100%; }
    .header { background: linear-gradient(135deg, #0a2e2a 0%, #0d4a42 60%, #0f5c52 100%); padding: 32px 24px 26px; text-align: center; }
    .header-title { color: #ffffff; font-size: 22px; font-weight: 700; letter-spacing: 1px; }
    .header-subtitle { color: #7ecfc4; font-size: 11px; margin-top: 6px; letter-spacing: 2.5px; text-transform: uppercase; }
    .body { padding: 28px 24px; }
    .greeting { font-size: 17px; font-weight: 700; color: #111; margin-bottom: 12px; }
    .message { font-size: 14px; color: #555; line-height: 1.75; margin-bottom: 24px; }
    .detail-box { background-color: #f7faf9; border: 1px solid #e3ece9; border-radius: 12px; padding: 4px 20px; margin-bottom: 24px; }
    .detail-row { display: table; width: 100%; padding: 12px 0; border-bottom: 1px solid #eef2f1; }
    .detail-row:last-child { border-bottom: none; }
    .detail-label { display: table-cell; font-size: 11px; color: #999; text-transform: uppercase; letter-spacing: 1px; width: 90px; vertical-align: top; padding-top: 2px; }
    .detail-value { display: table-cell; font-size: 14px; color: #222; font-weight: 600; white-space: pre-wrap; }
    .cta-wrap { text-align: center; margin-bottom: 28px; }
    .cta-button { display: inline-block; background: linear-gradient(135deg, #0a2e2a, #0f5c52); color: #ffffff !important; text-decoration: none; font-size: 14px; font-weight: 700; padding: 13px 32px; border-radius: 8px; letter-spacing: 0.3px; }
    .divider { border: none; border-top: 1px solid #f0f0f0; margin: 0 0 22px; }
    .note { background-color: #fffbef; border-left: 3px solid #f0a500; padding: 12px 14px; border-radius: 6px; margin-bottom: 8px; }
    .note p { font-size: 13px; color: #7a5c00; line-height: 1.65; }
    .footer { background-color: #f7f8f9; border-top: 1px solid #ececec; padding: 20px 24px; text-align: center; }
    .footer p { font-size: 11px; color: #bbb; line-height: 1.9; }
    .footer a { color: #0d4a42; font-weight: 600; text-decoration: none; }
  </style>
</head>
<body>
  <div class="wrapper">
    <div class="container">
      <div class="header">
        <div class="header-title">Supershyft</div>
        <div class="header-subtitle">Support Notification</div>
      </div>
      <div class="body">
        <p class="greeting">Hi ${escapeHtml(adminName)},</p>
        <p class="message">A user has submitted a support query. Details are below &mdash; please follow up as soon as possible.</p>
        <div class="detail-box">
          <div class="detail-row"><div class="detail-label">Ticket</div><div class="detail-value">#${escapeHtml(ticketId)}</div></div>
          <div class="detail-row"><div class="detail-label">Name</div><div class="detail-value">${escapeHtml(userName)}</div></div>
          <div class="detail-row"><div class="detail-label">Phone</div><div class="detail-value">${escapeHtml(userPhone)}</div></div>
          <div class="detail-row"><div class="detail-label">Email</div><div class="detail-value">${escapeHtml(userEmail)}</div></div>
          <div class="detail-row"><div class="detail-label">Query</div><div class="detail-value">${escapeHtml(queryText)}</div></div>
        </div>
        <div class="cta-wrap"><a href="${adminPanelUrl}" class="cta-button">View Support Tickets</a></div>
        <hr class="divider">
        <div class="note"><p><strong>Action needed:</strong> This user is waiting on a response. Please reach out via phone or email at your earliest convenience.</p></div>
      </div>
      <div class="footer">
        <p>Automated alert from <strong style="color:#444;">Supershyft</strong></p>
        <p style="margin-top:10px;"><a href="https://www.supershyft.com">www.supershyft.com</a></p>
        <p style="margin-top:10px;">This is an automated email. Please do not reply directly to this message.</p>
      </div>
    </div>
  </div>
</body>
</html>`;

return {
  json: {
    notification_id: data.notification_id,
    to: data.email,
    subject: `New support query #${ticketId} from ${userName}`,
    htmlBody
  }
};
